import React, { useEffect, useMemo, useState } from 'react';
import { ProductType } from '../services/api';

interface AssetTreePanelProps {
  productTypes: ProductType[];
  selectedCategory: string;
  onSelectCategory: (category: string) => void;
  loading?: boolean;
  error?: string | null;
}

type ProductTypeTreeNode = ProductType & {
  children: ProductTypeTreeNode[];
};

const getParentProductTypeId = (value: unknown) => {
  if (!value) {
    return '';
  }

  if (typeof value === 'object' && value !== null && 'id' in value) {
    return String((value as ProductType).id);
  }

  return String(value);
};

const AssetTreePanel: React.FC<AssetTreePanelProps> = ({
  productTypes,
  selectedCategory,
  onSelectCategory,
  loading,
  error,
}) => {
  const [rootExpanded, setRootExpanded] = useState(true);
  const [expandedProductTypeIds, setExpandedProductTypeIds] = useState<Set<string>>(new Set());

  const productTypeTree = useMemo(() => {
    const nodeMap = new Map<string, ProductTypeTreeNode>();
    const roots: ProductTypeTreeNode[] = [];

    productTypes.forEach((productType) => {
      nodeMap.set(productType.id, { ...productType, children: [] });
    });

    nodeMap.forEach((node) => {
      const parentId = getParentProductTypeId(node.parent_product_type);
      const parent = parentId ? nodeMap.get(parentId) : null;

      if (parent) {
        parent.children.push(node);
      } else {
        roots.push(node);
      }
    });

    const sortNodes = (nodes: ProductTypeTreeNode[]) => {
      nodes.sort((a, b) => a.display_name.localeCompare(b.display_name));
      nodes.forEach((node) => sortNodes(node.children));
    };

    sortNodes(roots);
    return roots;
  }, [productTypes]);

  useEffect(() => {
    setExpandedProductTypeIds(new Set(productTypes.map((productType) => productType.id)));
  }, [productTypes]);

  const handleToggleProductType = (productTypeId: string) => {
    setExpandedProductTypeIds((currentIds) => {
      const nextIds = new Set(currentIds);

      if (nextIds.has(productTypeId)) {
        nextIds.delete(productTypeId);
      } else {
        nextIds.add(productTypeId);
      }

      return nextIds;
    });
  };

  const renderProductTypeNode = (node: ProductTypeTreeNode, depth = 0) => {
    const hasChildren = node.children.length > 0;
    const expanded = expandedProductTypeIds.has(node.id);
    const selected = selectedCategory === node.id;

    return (
      <div key={node.id}>
        <div
          className={`flex items-center rounded-md text-sm transition ${
            selected ? 'bg-slate-100 text-slate-950' : 'text-slate-700 hover:bg-slate-50'
          }`}
          style={{ paddingLeft: `${depth * 18 + 8}px` }}
        >
          <button
            type="button"
            onClick={() => hasChildren && handleToggleProductType(node.id)}
            className="flex h-8 w-6 shrink-0 items-center justify-center text-slate-500"
            aria-label={expanded ? `Collapse ${node.display_name}` : `Expand ${node.display_name}`}
          >
            {hasChildren ? (expanded ? '\u25BE' : '\u25B8') : ''}
          </button>
          <button
            type="button"
            onClick={() => onSelectCategory(node.id)}
            className="min-w-0 flex-1 truncate py-2 pr-3 text-left"
            title={node.display_name}
          >
            {node.display_name}
          </button>
        </div>
        {hasChildren && expanded && node.children.map((childNode) => renderProductTypeNode(childNode, depth + 1))}
      </div>
    );
  };

  return (
    <div className="w-full max-w-[250px] rounded-lg border border-slate-200 bg-white shadow-sm">
      <div className="border-b border-slate-200 px-4 py-3">
        <div className="text-sm font-semibold text-slate-900">Product Types</div>
      </div>

      <div className="h-[calc(100vh-240px)] overflow-auto px-2 py-3">
        <button
          type="button"
          onClick={() => {
            onSelectCategory('All Assets');
            setRootExpanded((value) => !value);
          }}
          className={`flex w-full items-center rounded-md px-2 py-2 text-left text-sm font-semibold transition ${
            selectedCategory === 'All Assets' ? 'bg-slate-100 text-slate-950' : 'text-slate-900 hover:bg-slate-50'
          }`}
        >
          <span className="mr-2 flex h-5 w-5 items-center justify-center text-slate-500">
            {rootExpanded ? '\u25BE' : '\u25B8'}
          </span>
          <span className="truncate">All Assets</span>
        </button>

        {rootExpanded && (
          <div className="mt-1 space-y-0.5">
            {loading && <div className="px-3 py-3 text-sm text-slate-500">Loading product types...</div>}
            {!loading && error && <div className="px-3 py-3 text-sm text-red-600">{error}</div>}
            {!loading && !error && productTypeTree.length === 0 && (
              <div className="px-3 py-3 text-sm text-slate-500">No product types found</div>
            )}
            {!loading && !error && productTypeTree.map((node) => renderProductTypeNode(node))}
          </div>
        )}
      </div>
    </div>
  );
};

export default AssetTreePanel;
